/**
 * User Module Public API
 *
 * Centralized exports for the User module.
 * Import from this file when using user module functionality
 * from other parts of the application.
 *
 * @module modules/_core/user
 *
 * @example
 * ```typescript
 * import {
 *   UserModule,
 *   UserService,
 *   userRoutes,
 *   type User,
 *   type CreateUserRequest,
 * } from '@/modules/_core/user';
 * ```
 */

// -----------------------------------------------------------------------------
// Module Definition
// -----------------------------------------------------------------------------

export { UserModule, default } from '@/modules/_core/user/user.module';
export type {
  UserModuleContext,
  UserModuleHooks,
} from '@/modules/_core/user/user.module';

// -----------------------------------------------------------------------------
// Service
// -----------------------------------------------------------------------------

export { UserService } from '@/modules/_core/user/user.service';

// -----------------------------------------------------------------------------
// Repository
// -----------------------------------------------------------------------------

export { UserRepository } from '@/modules/_core/user/user.repository';
export type {
  PaginatedResult,
  CreateUserData,
  UpdateUserData,
} from '@/modules/_core/user/user.repository';

// -----------------------------------------------------------------------------
// Controller
// -----------------------------------------------------------------------------

export { UserController } from '@/modules/_core/user/user.controller';

// -----------------------------------------------------------------------------
// Routes
// -----------------------------------------------------------------------------

export {
  userRoutes,
  buildUserApiPath,
  buildUserAdminPath,
  isProtectedUserRoute,
  userEndpoints,
} from '@/modules/_core/user/user.routes';
export type {
  UserRouteConfig,
  UserEndpointMetadata,
} from '@/modules/_core/user/user.routes';

// -----------------------------------------------------------------------------
// Types
// -----------------------------------------------------------------------------

// Core entity types
export type {
  User,
  SafeUser,
  UserWithRelations,
  UserRoleInfo,
} from '@/modules/_core/user/user.types';

// Profile types
export type { UserProfile } from '@/modules/_core/user/user.types';

// Request/Response types
export type {
  CreateUserRequest,
  CreateUserResponse,
  UpdateUserRequest,
  UpdateUserResponse,
  UpdateProfileRequest,
  UpdateProfileResponse,
  ChangePasswordRequest,
  ChangePasswordResponse,
  ChangeStatusRequest,
  ChangeStatusResponse,
  AssignRoleRequest,
  AssignRoleResponse,
  RemoveRoleRequest,
  RemoveRoleResponse,
  InviteUserRequest,
  InviteUserResponse,
  UserSummary,
} from '@/modules/_core/user/user.types';

// Query/Filter types
export type {
  UserListFilters,
  UserListParams,
} from '@/modules/_core/user/user.types';

// Event types
export type {
  UserCreatedEvent,
  UserUpdatedEvent,
  UserDeletedEvent,
  UserStatusChangedEvent,
  RoleAssignedEvent,
  RoleRemovedEvent,
  PasswordChangedEvent,
  ProfileUpdatedEvent,
} from '@/modules/_core/user/user.types';

// Hook context types
export type {
  BeforeCreateContext,
  AfterCreateContext,
  BeforeUpdateContext,
  AfterUpdateContext,
} from '@/modules/_core/user/user.types';

// Module settings types
export type { UserModuleSettings } from '@/modules/_core/user/user.types';

// Type guards and helper functions
export {
  isUser,
  isSafeUser,
  toSafeUser,
  toUserProfile,
} from '@/modules/_core/user/user.types';

// -----------------------------------------------------------------------------
// Schemas (Zod validation)
// -----------------------------------------------------------------------------

export {
  // Base schemas
  emailSchema,
  passwordSchema,
  nameSchema,
  phoneSchema,
  urlSchema,
  cuidSchema,

  // CRUD schemas
  createUserSchema,
  updateUserSchema,
  updateProfileSchema,
  changePasswordSchema,
  changeStatusSchema,
  assignRoleSchema,
  removeRoleSchema,
  inviteUserSchema,

  // Query schemas
  userListQuerySchema,
  userIdSchema,

  // Response schemas
  safeUserResponseSchema,
  userProfileResponseSchema,
  userSummarySchema,

  // Module settings schema
  userModuleSettingsSchema,

  // Utility functions
  isValidEmail,
  validatePassword,
  normalizeName,
  getFullName,
  getInitials,
} from '@/modules/_core/user/user.schema';

export type {
  CreateUserInput,
  UpdateUserInput,
  UpdateProfileInput,
  ChangePasswordInput,
  ChangeStatusInput,
  AssignRoleInput,
  RemoveRoleInput,
  InviteUserInput,
  UserListQueryInput,
  UserIdInput,
  UserModuleSettingsInput,
} from '@/modules/_core/user/user.schema';
